// Generated by Liminal FlowField
// Particles: 500, Scale: 0.005, Speed: 2


let particles = [];
let cols, rows;
let scl = 20;
let zoff = 0;

function setup() {
  createCanvas(800, 600);
  cols = floor(width / scl);
  rows = floor(height / scl);

  for (let i = 0; i < 500; i++) {
    particles.push(new FlowParticle());
  }
}

function draw() {
  background(0, 0, 0, 10);

  for (let particle of particles) {
    let x = particle.pos.x;
    let y = particle.pos.y;

    let col = floor(x / scl);
    let row = floor(y / scl);

    col = constrain(col, 0, cols - 1);
    row = constrain(row, 0, rows - 1);

    let angle = noise(col * 0.005, row * 0.005, zoff) * TWO_PI * 4;
    let v = p5.Vector.fromAngle(angle);
    v.setMag(2);

    particle.applyForce(v);
    particle.update();
    particle.edges();
    particle.show(color(random(50, 150), random(100, 200), 255, 200));
  }

  zoff += 0.001;
}

class FlowParticle {
  constructor() {
    this.pos = createVector(random(width), random(height));
    this.vel = p5.Vector.random2D();
    this.acc = createVector(0, 0);
    this.maxSpeed = 3;
    this.prevPos = this.pos.copy();
  }

  applyForce(force) {
    this.acc.add(force);
  }

  update() {
    this.vel.add(this.acc);
    this.vel.limit(this.maxSpeed);
    this.prevPos = this.pos.copy();
    this.pos.add(this.vel);
    this.acc.mult(0);
  }

  edges() {
    if (this.pos.x > width) { this.pos.x = 0; this.prevPos.x = 0; }
    if (this.pos.x < 0) { this.pos.x = width; this.prevPos.x = width; }
    if (this.pos.y > height) { this.pos.y = 0; this.prevPos.y = 0; }
    if (this.pos.y < 0) { this.pos.y = height; this.prevPos.y = height; }
  }

  show(col) {
    stroke(col);
    strokeWeight(1);
    line(this.pos.x, this.pos.y, this.prevPos.x, this.prevPos.y);
  }
}